        final uri = DeepLinkService.buildUri(
          moduleId: 'mandelbrot',
          params: {
            'iterations': true,
            'colorScheme': Object(),
            'bailout': 'not-a-number',
            'power': double.nan,
            'juliaX': double.infinity,
            'juliaY': false,
